21	// Render a thrown client-side error's message under the friendly headline,
22	// but only in development. Mirrors the server-side `devErrorDetail` helper.
23	function clientErrorDetail(err: unknown): string | null {
24	  if (process.env.NODE_ENV === "production") return null;
25	  if (err instanceof Error) return err.message;
26	  return String(err);
27	}
28	
29	// Error codes the server actions can return. Anything else falls through to
30	// the generic "fallback" message.
31	const KNOWN_ERROR_CODES = new Set([
32	  "unauthenticated",
33	  "invalid_input",
34	  "slug_taken",
