                  >
                    {body}
                  </Link>
                ) : (
                  <div className="flex items-center justify-between gap-3 rounded-xl border border-border bg-card px-5 py-4">
                    {body}
                  </div>
                )}
              </li>
            );
          })}
        </ul>
      )}
    </main>
  );
}

