                  >
                    {body}
                  </Link>
                ) : (
                  <div className="flex flex-1 items-center justify-between gap-3 px-5 py-4">
                    {body}
                  </div>
                )}
                {ext.visibility === "draft" && (
                  <div className="flex items-center pr-3">
                    <DiscardButton
                      extensionId={ext.id}
                      extensionName={ext.name}
                    />
                  </div>
                )}
              </li>
            );
          })}
        </ul>
      )}
    </main>
  );
}

