function flattenDepts(list: Department[], depth = 0): { id: string; label: string }[] {
  const out: { id: string; label: string }[] = [];
  for (const d of list) {
    out.push({ id: d.id, label: "  ".repeat(depth) + d.name });
    if (d.children) out.push(...flattenDepts(d.children, depth + 1));
  }
  return out;
}

