          <input className={inputCls} {...field("nameZh")} />
        </div>
      </div>

      {/* Category + Scope */}
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className={labelCls}>{t("category")} *</label>
          <select className={inputCls} {...field("category")}>
            {(["skills", "mcp", "slash", "plugins"] as const).map((c) => (
