    expect(result).toEqual({
      ok: true,
      draft: {
        extensionId: "ext-1",
        versionId: "v-1",
        slug: "my-skill",
        version: "1.0.0",
        name: "My Skill",
        category: "skills",
        visibility: "draft",
        versionStatus: "pending",
        bundleUploaded: true,
      },
    });
  });

  it("reports bundleUploaded: false when bundleFileId is null", async () => {
    getSessionMock.mockResolvedValue({ user: { id: "user-A" } });
    selectMock.mockReturnValue(
      selectChain([
        {
          extensionId: "ext-1",
          publisherUserId: "user-A",
          slug: "my-skill",
          name: "My Skill",
          category: "skills",
          visibility: "draft",
          versionId: "v-1",
          version: "1.0.0",
          versionStatus: "pending",
          bundleFileId: null,
        },
      ]),
    );
    const result = await getDraft("ext-1");
    expect(result.ok).toBe(true);
    if (result.ok) expect(result.draft.bundleUploaded).toBe(false);
  });
});

