"use client";

import { AlertCircle } from "lucide-react";
import { useTranslations } from "next-intl";
import { useEffect } from "react";

interface Props {
  error: Error & { digest?: string };
  reset: () => void;
}

export default function ExtensionsListingError({ error, reset }: Props) {
  const t = useTranslations("extensions.errorBoundary");

  useEffect(() => {
    console.error("[extensions/listing]", error);
  }, [error]);

  return (
    <div className="px-7 py-12">
      <div className="border-border bg-card/40 mx-auto flex max-w-md flex-col items-center gap-4 rounded-lg border border-dashed p-10 text-center">
        <AlertCircle className="text-destructive size-8" />
        <h2 className="text-foreground text-base font-semibold">
          {t("title")}
        </h2>
        <p className="text-muted-foreground max-w-sm text-[13.5px] leading-relaxed">
          {t("body")}
        </p>
        <button
          type="button"
          onClick={reset}
          className="bg-primary text-primary-foreground hover:opacity-90 mt-1 rounded-md px-4 py-2 text-[13px] font-semibold transition-opacity"
        >
          {t("retry")}
        </button>
        {error.digest && (
          <code className="text-muted-foreground mt-1 font-mono text-[10.5px]">
            {error.digest}
          </code>
        )}
      </div>
    </div>
  );
}

